// Filter topics from the Topics sheet and pick a RANDOM available one.
// Sheet columns: Topic | Last Used | Date Added
// Rules:
// - Skip topics already used (Last Used not blank)
// - Skip topics older than 7 days (Date Added > 7 days ago)
// - Topics with no Date Added (manually added) are always available
// - Pick randomly among available topics so we don't always run them in sheet order

const rows = $input.all();
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const available = rows.filter(row => {
  const lastUsed = row.json['Last Used'];
  const dateAdded = row.json['Date Added'];

  // Skip if already used
  if (lastUsed && String(lastUsed).trim() !== '') return false;

  // Skip if has a date and it's older than 7 days (old news)
  if (dateAdded && String(dateAdded).trim() !== '') {
    const addedDate = new Date(dateAdded);
    if (addedDate < sevenDaysAgo) return false;
  }

  return true;
});

if (available.length === 0) {
  throw new Error('No available topics — all topics have been used or are older than 7 days. New topics will be added automatically from Slack or the AI Topic Generator sub-workflow.');
}

// Random pick instead of sheet order
const randomIndex = Math.floor(Math.random() * available.length);
return [available[randomIndex]];

// Create one item per platform using the picked topic and tone & voice text.
// Currently LinkedIn only — BRDGIT does not have Instagram or Facebook access.
// To re-enable multi-platform, add platform names to the array below and add
// matching channel keys in the "Format Post for HubSpot" node.
const topic = $('Pick Next Topic').first().json.Topic;
const toneText = $('Extract Tone & Voice Text1').first().json.data;

const platforms = ['LinkedIn'];

return platforms.map(platform => ({
  json: {
    platform,
    topic,
    contentType: 'organic_post',
    toneText
  }
}));

// Parse LLM output and build the HubSpot draft payload for LinkedIn.
// LinkedIn-only — BRDGIT does not have Instagram or Facebook access at this time.
// Defensive dedup: some LLM outputs repeat the headline at the top of the body,
// which would cause the final caption to print the headline twice. We detect
// and strip that case before concatenating.
const raw = $input.first().json.output || $input.first().json.message?.content || $input.first().json.content || $input.first().json;

let post;
try {
  const cleaned = typeof raw === 'string' ? raw.replace(/```json\n?|```\n?/g, '').trim() : raw;
  post = typeof cleaned === 'string' ? JSON.parse(cleaned) : cleaned;
} catch (e) {
  throw new Error('LLM did not return valid JSON: ' + raw);
}

// HubSpot LinkedIn channel key (from HubSpot → Settings → Social → Connected Accounts)
const channelKey = 'LinkedInCompanyPage:108300227';

const headline = String(post.headline || '').trim();
let body = String(post.body || '').trim();
const cta = String(post.cta || '').trim();

// Defensive dedup #1: body starts with the headline (case-insensitive) — strip it.
// Also handles a trailing period/dash/etc plus whitespace/newlines.
if (headline && body.toLowerCase().startsWith(headline.toLowerCase())) {
  body = body.substring(headline.length).replace(/^[\s.,;:\-—–\n]+/, '').trim();
}

// Defensive dedup #2: cta is identical to (or contained in) the body — don't double-print.
// Only strip cta from body if the body literally ends with the cta text.
if (cta && body.toLowerCase().endsWith(cta.toLowerCase())) {
  body = body.substring(0, body.length - cta.length).replace(/[\s.,;:\-—–\n]+$/, '').trim();
}

// Build the caption: headline + body + CTA, plus the source URL if present + valid
const parts = [headline, body, cta].filter(Boolean);

const rawUrl = typeof post.sourceUrl === 'string' ? post.sourceUrl.trim() : '';
const hasValidUrl = rawUrl && /^https?:\/\//i.test(rawUrl);
if (hasValidUrl) {
  parts.push(rawUrl);
}

const fullCaption = parts.join('\n\n').trim();

return [{
  json: {
    headline,
    body,
    hashtags: post.hashtags,
    cta,
    sourceUrl: hasValidUrl ? rawUrl : null,
    suggested_image_prompt: post.suggested_image_prompt,
    fullCaption,
    platform: 'LinkedIn',
    topic: post.topic,
    channelKey
  }
}];
